        { referencia: "Oséias 2:19-20", descricao: "referido em 2 Coríntios 11:2; Efésios 5:25-27 - noiva de Cristo." },
        { referencia: "Oséias 2:23", descricao: "citado em Romanos 9:25-26; 1 Pedro 2:10 - inclusão dos gentios." }
